const rows = msg.payload || [];
const now = new Date();
const hour = now.getHours() + now.getMinutes() / 60;

function pvFactor(h) {
    if (h < 6 || h > 21) return 0;
    const t = (h - 6) / 15;
    return Math.max(0, Math.sin(Math.PI * t));
}

const soc = flow.get('soc') || {};
const points = [];

for (const row of rows) {
    const bid = row.building_id;
    const installed = parseFloat(row.installed_kwp) || 6.0;

    const pv = +(installed * pvFactor(hour) * (0.85 + Math.random() * 0.2)).toFixed(3);
    const eveningBoost = (hour > 18 && hour < 22) ? 0.8 : 0;
    const load = +(0.4 + Math.random() * 0.6 + eveningBoost).toFixed(3);
    const ev = (hour > 17 && hour < 23 && Math.random() > 0.5) ? 3.5 : 0;
    const heatpump = ((hour < 8 || hour > 18) && Math.random() > 0.4)
        ? +(1 + Math.random() * 1).toFixed(3) : 0;

    if (soc[bid] === undefined) soc[bid] = 50 + Math.random() * 30;
    soc[bid] = Math.max(10, Math.min(95, soc[bid] + (Math.random() - 0.5) * 3));

    const totalLoad = load + ev + heatpump;
    const surplus = pv - totalLoad;
    let battery = 0;
    if (surplus > 0.3 && soc[bid] < 90) battery = Math.min(surplus, 3.0);
    else if (surplus < -0.3 && soc[bid] > 20) battery = Math.max(surplus, -3.0);
    battery = +battery.toFixed(3);

    const grid = +(pv - totalLoad - Math.max(0, battery)).toFixed(3);
    const exportKw = grid > 0 ?  grid : 0;
    const importKw = grid < 0 ? -grid : 0;
    const selfConsumption = +Math.max(0,
        Math.min(pv, totalLoad + Math.max(0, battery))
    ).toFixed(3);

    points.push({
        measurement: 'sigen',
        tags: { org_id: row.org_id, site_id: row.site_id, building_id: bid, source: 'mock' },
        fields: {
            pv_kw: pv, load_kw: load, ev_charger_kw: ev, heatpump_kw: heatpump,
            battery_kw: battery, battery_soc: +soc[bid].toFixed(1),
            grid_kw: grid, export_kw: exportKw, import_kw: importKw,
            self_consumption_kw: selfConsumption,
        },
    });
}

flow.set('soc', soc);
node.status({ fill: 'green', shape: 'dot', text: `${points.length} buildings @ ${now.toLocaleTimeString()}` });
msg.payload = points;
return msg;

const points = msg.payload || [];
if (points.length === 0) {
    node.status({ fill: 'yellow', shape: 'ring', text: 'no points' });
    return null;
}
const tsMs = Date.now();
function escapeTag(value) {
    return String(value).replace(/([,= ])/g, '\\$1');
}
const lines = points.map(p => {
    const tags = Object.entries(p.tags).map(([k, v]) => `${escapeTag(k)}=${escapeTag(v)}`).join(',');
    const fields = Object.entries(p.fields).map(([k, v]) => `${k}=${v}`).join(',');
    return `${p.measurement},${tags} ${fields} ${tsMs}`;
});
msg.payload = lines.join('\n');
msg.headers = { 'Content-Type': 'text/plain; charset=utf-8' };
node.status({ fill: 'green', shape: 'dot', text: `${points.length} lines built` });
return msg;

// Router: if a token is configured, take the LIVE path.
// Otherwise fall back to MOCK. Same downstream — only the source
// tag in InfluxDB differs.

const token = env.get('ENTSOE_API_TOKEN');
const zone = env.get('ENTSOE_BIDDING_ZONE') || '10YBE----------2';

// Treat 'changeme-entsoe-token', empty, or anything obviously
// placeholder-y as 'no token'.
const hasRealToken = token && token.length > 10 && !token.startsWith('changeme');

msg.zone = zone;
msg.token = token;

if (hasRealToken) {
    node.status({ fill: 'green', shape: 'dot', text: 'live (entsoe)' });
    return [msg, null];     // -> LIVE
}
node.status({ fill: 'yellow', shape: 'ring', text: 'mock (no token)' });
return [null, msg];         // -> MOCK

// Build query for the next 24h day-ahead prices.
//
// ENTSO-E expects period bounds in YYYYMMDDhhmm UTC.
// Day-ahead prices: documentType=A44, in_Domain=out_Domain=<zone>
//
// Doc: https://documenter.getpostman.com/view/7009892/2s93JtP3F6

function fmt(d) {
    const pad = n => String(n).padStart(2, '0');
    return d.getUTCFullYear()
        + pad(d.getUTCMonth() + 1)
        + pad(d.getUTCDate())
        + pad(d.getUTCHours())
        + pad(d.getUTCMinutes());
}

// Fetch a 36h window: 12h backwards + 24h ahead. Gives us prices
// for the current hour and the next ones, with a small overlap.
const now = new Date();
const periodStart = new Date(now.getTime() - 12 * 3600 * 1000);
const periodEnd   = new Date(now.getTime() + 24 * 3600 * 1000);

const params = new URLSearchParams({
    documentType: 'A44',
    in_Domain: msg.zone,
    out_Domain: msg.zone,
    periodStart: fmt(periodStart),
    periodEnd: fmt(periodEnd),
    securityToken: msg.token,
});

msg.url = 'https://web-api.tp.entsoe.eu/api?' + params.toString();
msg.method = 'GET';
msg.headers = { 'Accept': 'application/xml' };
msg.zone_label = msg.zone.startsWith('10YBE') ? 'BE'
               : msg.zone.startsWith('10YNL') ? 'NL'
               : msg.zone.startsWith('10Y1001A1001A82H') ? 'DE-LU'
               : msg.zone.substring(0, 6);
node.status({ fill: 'blue', shape: 'dot', text: `→ ENTSO-E ${msg.zone_label}` });
return msg;

// Minimal XML parser tailored to ENTSO-E's Publication_MarketDocument
// response. We don't pull in a full XML library — extracting <Point>
// elements with regex is robust enough for this fixed schema.
//
// Response shape (abridged):
//   <Publication_MarketDocument>
//     <TimeSeries>
//       <Period>
//         <timeInterval>
//           <start>2026-05-26T22:00Z</start>
//           <end>2026-05-27T22:00Z</end>
//         </timeInterval>
//         <resolution>PT60M</resolution>
//         <Point>
//           <position>1</position>
//           <price.amount>45.67</price.amount>
//         </Point>
//         ... 23 more points ...
//       </Period>
//     </TimeSeries>
//   </Publication_MarketDocument>
//
// Each Period yields up to 24 hourly points starting at `start`.

if (msg.statusCode && msg.statusCode !== 200) {
    node.status({ fill: 'red', shape: 'dot', text: `HTTP ${msg.statusCode}` });
    node.warn(`ENTSO-E request failed: ${msg.statusCode} — ${(msg.payload || '').substring(0, 200)}`);
    return null;
}

const xml = msg.payload || '';

// Acknowledgement_MarketDocument means "no data" — fairly common
// e.g. when no day-ahead has been published yet.
if (xml.includes('Acknowledgement_MarketDocument')) {
    const reason = xml.match(/<text>([^<]*)<\/text>/);
    node.status({ fill: 'yellow', shape: 'ring', text: 'no data' });
    node.warn(`ENTSO-E: no data — ${reason ? reason[1] : 'unknown reason'}`);
    return null;
}

const points = [];
const periodRegex = /<Period>([\s\S]*?)<\/Period>/g;
let periodMatch;
while ((periodMatch = periodRegex.exec(xml)) !== null) {
    const period = periodMatch[1];
    const startMatch = period.match(/<start>([^<]+)<\/start>/);
    if (!startMatch) continue;
    const periodStart = new Date(startMatch[1]);

    // Resolution: PT60M (1h), PT30M, PT15M. We only handle PT60M
    // because day-ahead is always hourly in EU markets.
    const resMatch = period.match(/<resolution>(PT\d+M)<\/resolution>/);
    const stepMin = resMatch ? parseInt(resMatch[1].match(/\d+/)[0], 10) : 60;

    const pointRegex = /<Point>\s*<position>(\d+)<\/position>\s*<price\.amount>([\d.\-]+)<\/price\.amount>\s*<\/Point>/g;
    let pointMatch;
    while ((pointMatch = pointRegex.exec(period)) !== null) {
        const position = parseInt(pointMatch[1], 10);
        const price = parseFloat(pointMatch[2]);
        const ts = new Date(periodStart.getTime() + (position - 1) * stepMin * 60 * 1000);
        points.push({
            measurement: 'price',
            tags: { zone: msg.zone_label, source: 'entsoe' },
            fields: { eur_per_mwh: price },
            timestamp_ms: ts.getTime(),
        });
    }
}

if (points.length === 0) {
    node.status({ fill: 'yellow', shape: 'ring', text: 'no points parsed' });
    node.warn('ENTSO-E XML parsed but yielded no Points');
    return null;
}

node.status({ fill: 'green', shape: 'dot', text: `${points.length} prices` });
msg.payload = points;
return msg;

// Realistic BE day-ahead price pattern, 24 hourly points covering
// the next 24h. Used as a fallback when ENTSO-E token is missing.
//
// Pattern (rough 2025/2026 BE shape):
//   Night (00-06): 30-50 EUR/MWh — baseload
//   Morning peak (07-09): 80-120 EUR/MWh
//   Midday solar dip (10-15): -10 to 40 EUR/MWh, occasionally negative
//   Evening peak (17-21): 100-180 EUR/MWh
//   Late evening (22-00): 50-80 EUR/MWh

function priceForHour(h) {
    let base;
    if (h < 6) base = 35 + Math.random() * 15;
    else if (h < 10) base = 80 + Math.random() * 40;
    else if (h < 16) {
        // Solar dip. ~15% chance of negative price in spring/summer.
        base = Math.random() < 0.15 ? -5 + Math.random() * -10 : 20 + Math.random() * 30;
    }
    else if (h < 17) base = 50 + Math.random() * 30;
    else if (h < 22) base = 100 + Math.random() * 80;
    else base = 50 + Math.random() * 30;
    return +base.toFixed(2);
}

const now = new Date();
// Align to the next whole hour
const startHour = new Date(now);
startHour.setMinutes(0, 0, 0);

const points = [];
for (let i = 0; i < 24; i++) {
    const ts = new Date(startHour.getTime() + i * 3600 * 1000);
    points.push({
        measurement: 'price',
        tags: { zone: 'BE', source: 'mock' },
        fields: { eur_per_mwh: priceForHour(ts.getHours()) },
        timestamp_ms: ts.getTime(),
    });
}

node.status({ fill: 'green', shape: 'dot', text: `24h mock @ ${now.toLocaleTimeString()}` });
msg.payload = points;
return msg;

// Same format as the energy flow, except each point can carry its
// own timestamp_ms (because we're writing future prices, not now-data).

const points = msg.payload || [];
if (points.length === 0) {
    node.status({ fill: 'yellow', shape: 'ring', text: 'no points' });
    return null;
}

function escapeTag(value) {
    return String(value).replace(/([,= ])/g, '\\$1');
}

const lines = points.map(p => {
    const tags = Object.entries(p.tags).map(([k, v]) => `${escapeTag(k)}=${escapeTag(v)}`).join(',');
    const fields = Object.entries(p.fields).map(([k, v]) => `${k}=${v}`).join(',');
    const ts = p.timestamp_ms || Date.now();
    return `${p.measurement},${tags} ${fields} ${ts}`;
});

msg.payload = lines.join('\n');
msg.headers = { 'Content-Type': 'text/plain; charset=utf-8' };
msg.method = 'POST';
node.status({ fill: 'green', shape: 'dot', text: `${points.length} lines built` });
return msg;
